  var BUILTIN_RULE_SOURCES2 = [["abandon-sessions", '---\nid: abandon-sessions\nname: Abandoned Sessions\ngroup: session-hygiene\nseverity: low\nscope: sessions\nversion: 1\ntags: [session, abandoned, single]\nthresholds:\n  maxAbandonRate: 0.4\n  minSample: 10\n---\n\n# Description\nDetects sessions with only a single message, indicating missed refinement opportunities.\n\n# When Triggered\n{{count}} sessions ({{pct}}) have only 1 message. You may be missing refinement opportunities.\n\n# How to Improve\nUse follow-up messages to refine Copilot\'s responses. Iterating produces much better results than one-shot prompts.\n\n# Examples\n{{extra.workspace}}: "{{message}}..."\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: requestCount == 1\naggregate: ratio\ncheck: ratio > thresholds.maxAbandonRate AND count > thresholds.minSample\nexamples: {{workspaceName}}: abandoned after 1 message\n```\n'], ["agent-mode-for-asks", '---\nid: agent-mode-for-asks\nname: Agent Mode for Simple Questions\ngroup: prompt-quality\nseverity: medium\nscope: requests\nrequiresIdeContext: true\nversion: 1\ntags: [agent, mode, routing, cost]\nthresholds:\n  maxMessageLength: 80\n  minSample: 10\n  maxRatio: 0.15\n---\n\n# Description\nDetects agent-mode requests with very short prompts that didn\'t trigger any tools, edits, or file context. These look like simple questions that would be cheaper and faster in Ask/Chat mode without the agent loop overhead.\n\n# When Triggered\n{{count}} agent-mode requests ({{pct}}) were trivially short ({{extra.maxMessageLength}} chars) with no tool calls, file edits, or code output. Routing simple questions through agent mode pays for the agent loop without using its capabilities.\n\n# How to Improve\nUse Ask/Chat mode for quick questions ("what does this error mean?", "how do I do X?"). Reserve agent mode for tasks that need to run terminal commands, edit files, or coordinate multiple steps.\n\n# Examples\n"{{messageText | truncate:60}}" ({{messageLength}} chars, agent mode)\n\n# Detection Logic\n```detect\nscan: requests\nmatch: agentMode == "agent" AND messageLength > 0 AND messageLength < thresholds.maxMessageLength AND length(toolsUsed) == 0 AND length(aiCode) == 0 AND length(referencedFiles) == 0 AND length(editedFiles) == 0 AND isCanceled == false\naggregate: ratio\ncheck: ratio > thresholds.maxRatio AND count > thresholds.minSample\nexamples: "{{messageText | truncate:60}}" ({{messageLength}} chars)\n```\n\n# Tests\n```test\n{agentMode: "agent", messageText: "what is jwt?", messageLength: 12, toolsUsed: [], aiCode: [], referencedFiles: [], editedFiles: [], isCanceled: false} -> triggered\n{agentMode: "agent", messageText: "fix bug", messageLength: 7, toolsUsed: ["edit_file"], aiCode: [], referencedFiles: [], editedFiles: [], isCanceled: false} -> clean\n{agentMode: "chat", messageText: "what is jwt?", messageLength: 12, toolsUsed: [], aiCode: [], referencedFiles: [], editedFiles: [], isCanceled: false} -> clean\n```\n'], ["agentic-no-tools", '---\nid: agentic-no-tools\nname: Agentic Without Tools\ngroup: tool-mastery\nseverity: low\nscope: requests\nrequiresIdeContext: true\nversion: 1\ntags: [tools, agent, effectiveness]\nthresholds:\n  minSample: 10\n---\n\n# Description\nDetects agentic requests that used no tools, reducing the effectiveness of agent mode.\n\n# When Triggered\n{{count}} agentic requests used no tools. Agent mode is most effective when tools are enabled.\n\n# How to Improve\nEnsure tools are enabled in agent mode for file search, terminal access, and web search capabilities.\n\n# Examples\n{{extra.agentName}}: "{{message}}..."\n\n# Detection Logic\n```detect\nscan: requests\nmatch: (agentMode == "agent" OR agentName != "") AND toolsUsed.length == 0\naggregate: count\ncheck: count > thresholds.minSample\nexamples: "{{messageText | truncate:60}}"\n```\n'], ["auto-approve-terminal", "---\nid: auto-approve-terminal\nname: Auto-Approved Terminal Commands\ngroup: code-review\nseverity: medium\nscope: requests\nrequiresIdeContext: true\nversion: 1\ntags: [review, security, terminal, auto-approve]\nthresholds:\n  minAutoApprove: 20\n  minTerminalAutoApprove: 10\n---\n\n# Description\nDetects terminal commands that were auto-approved without review, which can be risky for destructive operations.\n\n# When Triggered\n{{count}} terminal commands were auto-approved. Blindly running AI-generated commands can be risky.\n\n# How to Improve\nReview terminal commands before execution, especially destructive ones (rm, git push --force, DROP TABLE). Use session-scoped approval cautiously.\n\n# Examples\n$ {{extra.command}}\n\n# Detection Logic\n```detect\nscan: requests\nmatch: toolConfirmations.length > 0\naggregate: count\nstats: autoApproveStats(matched)\nemitCount: stats.terminalAutoApproved\nemitTotal: stats.withConfirmations\ncheck: stats.terminalAutoApproved > thresholds.minTerminalAutoApprove AND stats.autoApprovedTotal > thresholds.minAutoApprove\n```\n"], ["auto-avoidance", '---\nid: auto-avoidance\nname: Auto Model Avoidance\ngroup: tool-mastery\nseverity: medium\nscope: requests\nversion: 1\ntags: [model, auto, routing, cost]\nthresholds:\n  minTopShare: 0.6\n  minSample: 30\n---\n\n# Description\nDetects users who pin a single premium model for every request and never let auto-routing pick a cheaper model when one would suffice. Auto routing handles many requests with smaller models for the same outcome.\n\n# When Triggered\n{{pct}} of requests use {{extra.topModel}} (a premium model) and no requests use auto routing. Pinning a top-tier model for every task overpays on simple work.\n\n# How to Improve\nSwitch the default to "auto" or use the model picker. Reserve specific top-tier models (Claude Opus, GPT-5) for hard reasoning, planning, or large-context tasks. For routine edits and questions, the lighter model auto picks is usually enough.\n\n# Examples\n{{extra.topModel}}: {{extra.topCount}} requests ({{pct}})\n\n# Detection Logic\n```detect\nscan: requests\nmatch: modelId != ""\naggregate: count\nmodels: modelStats(matched)\ntopModel: models.topModel\ntopCount: models.topCount\nhasAutoUsage: countWhere(matched, "modelId", "matches", "(?i)auto")\nemitCount: models.topCount\nemitTotal: models.total\ncheck: models.topShare > thresholds.minTopShare AND modelTier(models.topModel) >= 1 AND hasAutoUsage == 0 AND models.total > thresholds.minSample\n```\n'], ["broken-flow-state", "---\nid: broken-flow-state\nname: Broken Flow State\ngroup: session-hygiene\nseverity: medium\nscope: sessions\nversion: 1\ntags: [session, flow, focus, interruptions]\nthresholds:\n  rapidFollowupSec: 30\n  sessionMinReqs: 3\n  shallowScore: 25\n  lowScoreRate: 0.6\n  minDays: 5\n---\n\n# Description\nDetects fragmented coding flow with long pauses between prompts, indicating frequent context switches, interruptions, or multitasking.\n\n# When Triggered\n{{count}}/{{extra.totalDays}} days ({{pct}}) show fragmented flow -- long pauses between prompts, short scattered work blocks.\nAverage flow score: {{extra.avgScore}}/100.\nThis anti-pattern indicates frequent context switches, interruptions, or multitasking that prevent deep coding flow.\n\n# How to Improve\nBlock 2+ hour uninterrupted time slots for AI-assisted coding.\nClose Slack / email / notifications during coding sessions.\nPre-plan your next prompt while the agent works on the current one.\nBatch meetings to protect contiguous coding blocks.\nUse the Flow State page to find your most productive hours.\n\n# Examples\n{{extra.date}}: avg flow score {{extra.flowScore}}/100\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: requestCount >= thresholds.sessionMinReqs\naggregate: count\nflow: flowScoreStats(allSessions, thresholds.sessionMinReqs, thresholds.rapidFollowupSec * 1000)\nemitCount: flow.fragmentedDays\nemitTotal: flow.totalDays\ntotalDays: flow.totalDays\navgScore: flow.avgScore\ncheck: flow.lowScoreRate > thresholds.lowScoreRate AND flow.totalDays >= thresholds.minDays\nseverity: flow.lowScoreRate > 0.8\nexamples: {{workspaceName}}: flow disruption detected\n```\n"], ["cache-hit-starvation", '---\nid: cache-hit-starvation\nname: Prompt Cache Starvation\ngroup: tool-mastery\nseverity: medium\nscope: requests\nversion: 1\ntags: [tokens, cache, context, cost]\nthresholds:\n  minPromptTokens: 5000\n  minSample: 20\n  minCacheRate: 0.1\n---\n\n# Description\nDetects requests with large prompts (>5K input tokens) where almost none of the prompt is being served from the model\'s prompt cache. Low cache hit rates mean every request pays full price for the same prefixes \u2014 usually caused by churning instructions, frequent compaction, or unstable system prompts.\n\n# When Triggered\n{{count}} requests had prompts >{{extra.minPromptTokens}} tokens but only {{extra.cachePctLabel}} of input tokens came from cache. Each long-prompt request is paying full price for context the model has seen before.\n\n# How to Improve\nStabilize the front of your prompts: keep custom instructions short and stable, avoid frequent compaction, prefer file references over pasted code, and avoid clearing chat mid-task. Within a session, repeated prefixes get cached and re-used for free.\n\n# Examples\n{{promptTokens}} prompt tokens \xB7 {{coalesce(cacheReadTokens, 0)}} cached\n\n# Detection Logic\n```detect\nscan: requests\nmatch: promptTokens > thresholds.minPromptTokens\naggregate: count\ntotalPrompt: sumField(matched, "promptTokens")\ntotalCache: sumField(matched, "cacheReadTokens")\ncacheRate: totalCache / totalPrompt\ncachePctLabel: cacheRate | pct:1\nemitCount: count\nemitTotal: count\ncheck: count > thresholds.minSample AND cacheRate < thresholds.minCacheRate\nexamples: {{promptTokens}} prompt tokens, {{coalesce(cacheReadTokens, 0)}} cached\n```\n'], ["caps-lock", '---\nid: caps-lock\nname: Caps Lock Rage\ngroup: prompt-quality\nseverity: medium\nscope: requests\nversion: 1\ntags: [prompt, frustration, caps]\nthresholds:\n  minLength: 10\n  capsRate: 0.9\n  minReqs: 1\n---\n\n# Description\nDetects requests written mostly or entirely in CAPS LOCK, indicating high frustration levels.\n\n# When Triggered\n{{count}} requests are written mostly or entirely in CAPS LOCK, indicating high frustration.\n\n# How to Improve\nAll-caps messages signal frustration. Step away, take a breath, then return with a calm, structured prompt. Clear communication gets better AI responses.\n\n# Examples\n"{{message}}"\n\n# Detection Logic\n```detect\nscan: requests\nmatch: messageLength >= thresholds.minLength AND capsLetterRatio(messageText) >= thresholds.capsRate\naggregate: count\ncheck: count >= thresholds.minReqs\nexamples: "{{messageText | truncate:80}}"\n```\n'], ["context-engineering-gaps", '---\nid: context-engineering-gaps\nname: Context Engineering Gaps\ngroup: prompt-quality\nseverity: medium\nscope: both\nversion: 1\ntags: [context, agents, skills, mcp, instructions]\nthresholds:\n  minReqs: 30\n  fileRefMinRate: 0.1\n  instructionMinRate: 0.05\n---\n\n# Description\nAudits your context engineering setup: custom agents, skills, MCP tools, file references, and custom instructions. Missing components limit AI effectiveness.\n\n# When Triggered\n{{count}} of 5 context engineering signals missing. Your AI lacks the context to be maximally effective.\n\n# How to Improve\nLevel up your context engineering: create AGENTS.md for custom agents, SKILL.md for domain knowledge, connect MCP tools, use #file references, and add .instructions.md with project conventions.\n\n# Examples\n{{extra.gapCount}} of 5 context engineering signals missing\n\n# Detection Logic\n```detect\nscan: requests\nmatch: true\naggregate: count\nreqCount: count\nhasSubAgents: someWhere(allReqs, "agentName", "!=", "") AND \\\n  someWhere(allReqs, "agentName", "!=", "copilot") AND \\\n  someWhere(allReqs, "agentMode", "agent")\nhasSkills: flatCount(allReqs, "skillsUsed") > 0\nhasMcp: flatSomeWhere(allReqs, "toolsUsed", ".", "mcp_", "startsWith")\nfileRefRate: countWhere(allReqs, "referencedFiles.length", ">", 0) / reqCount\ninstrRate: countWhere(allReqs, "customInstructions.length", ">", 0) / reqCount\ngap1: hasSubAgents == 0\ngap2: hasSkills == 0\ngap3: hasMcp == 0\ngap4: fileRefRate < thresholds.fileRefMinRate\ngap5: instrRate < thresholds.instructionMinRate\ngapCount: gap1 + gap2 + gap3 + gap4 + gap5\nemitCount: gapCount\nemitTotal: 5\ncheck: gapCount > 0 AND reqCount >= thresholds.minReqs\nseverity: gapCount >= 4\n```\n'], ["copy-paste-blindness", '---\nid: copy-paste-blindness\nname: Copy-Paste Blindness\ngroup: code-review\nseverity: high\nscope: sessions\nversion: 1\ntags: [review, copy-paste, blindness]\nthresholds:\n  minAiLoc: 50\n  minSessions: 3\n---\n\n# Description\nDetects sessions with large AI-generated code blocks that have no follow-up refinement, suggesting code is accepted without review.\n\n# When Triggered\n{{count}} sessions have large AI-generated code blocks with no follow-up refinement. Code may be accepted without review.\n\n# How to Improve\nAlways review AI-generated code before accepting. Ask follow-up questions to refine, test, and understand the output.\n\n# Examples\n{{extra.workspace}}: {{extra.aiLoc}} AI LOC, {{extra.messageCount}} messages, no refinement\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: requestCount >= 2 AND flatSumField(requests, "aiCode", "loc") >= thresholds.minAiLoc AND NOT (\\\n  anyWhere(slice(requests, 1), "messageText", "matches", "(?i)\\\\b(change|fix|modify|update|refactor|wrong|instead|actually|revert|redo|try again)\\\\b") OR \\\n  someWhere(slice(requests, 1), "editedFiles.length", ">", 0))\naggregate: count\ncheck: count >= thresholds.minSessions\nexamples: {{workspaceName}}: {{flatSumField(requests, "aiCode", "loc")}} AI LoC, no refinement\n```\n'], ["excessive-file-context", '---\nid: excessive-file-context\nname: Excessive File Context\ngroup: prompt-quality\nseverity: medium\nscope: requests\nversion: 1\ntags: [context, files, tokens, cost]\nthresholds:\n  minFiles: 30\n  minOutliers: 10\n  maxRatio: 0.005\n---\n\n# Description\nDetects outlier requests that attach a very large number of files to the prompt. Each referenced file expands the input context \u2014 and the agent rarely reads all of them. Bulk-attaching files is a common pattern when the user isn\'t sure which files are relevant; it works, but pays for context that\'s mostly never used.\n\n# When Triggered\n{{count}} request(s) attached \u2265{{thresholds.minFiles}} files to the prompt (largest: {{extra.maxFiles}} files). The model only reads a fraction of large attachments \u2014 the rest is paid-for context that contributes nothing.\n\n# How to Improve\nBe selective: attach only the 3\u20135 files most relevant to the task. Use `#codebase` or `#file:<glob>` patterns to let the model search on demand. For exploration tasks, ask the agent to `grep` first and read results into context only as needed.\n\n# Examples\n{{length(referencedFiles)}} files: "{{messageText | truncate:60}}"\n\n# Detection Logic\n```detect\nscan: requests\nmatch: length(referencedFiles) >= thresholds.minFiles\naggregate: ratio\nstats: excessFileContextStats(allReqs, thresholds.minFiles)\nmaxFiles: stats.maxFiles\np95Files: stats.p95Files\nemitCount: stats.outlierCount\nemitTotal: stats.totalReqs\ncheck: stats.outlierCount >= thresholds.minOutliers AND stats.ratio >= thresholds.maxRatio\nexamples: {{length(referencedFiles)}} files: "{{messageText | truncate:60}}"\n```\n'], ["frustration-signals", '---\nid: frustration-signals\nname: Frustration Signals\ngroup: prompt-quality\nseverity: medium\nscope: requests\nversion: 1\ntags: [prompt, frustration, caps, punctuation]\nthresholds:\n  capsRate: 0.4\n  minWords: 3\n  minReqs: 2\npatterns:\n  frustration: ["!{3,}", "\\\\?{3,}", "wtf|come on|why won\'t", "this is broken|doesn\'t work"]\n---\n\n# Description\nDetects requests showing frustration indicators like excessive punctuation (!!!?, ???) or ALL CAPS writing.\n\n# When Triggered\n{{count}} requests show frustration indicators (excessive punctuation, ALL CAPS). This usually means the approach isn\'t working.\n\n# How to Improve\nWhen frustrated, step back and change strategy. Start a new session, rephrase the problem, or break it into smaller pieces instead of escalating the same prompt.\n\n# Examples\n"{{message}}"\n\n# Detection Logic\n```detect\nscan: requests\nmatch: messageLength >= 10 AND (matchesAny(messageText, patterns.frustration) OR capsWordRatio(messageText, thresholds.minWords) >= thresholds.capsRate)\naggregate: count\ncheck: count >= thresholds.minReqs\nexamples: "{{messageText | truncate:80}}"\n```\n\n# Tests\n```test\n{messageText: "WHY WONT THIS WORK???!!!", messageLength: 25} -> triggered\n{messageText: "Please refactor the auth module", messageLength: 31} -> clean\n{messageText: "THIS IS SO BROKEN FIX IT NOW", messageLength: 28} -> triggered\n{messageText: "Add error handling to the API endpoint", messageLength: 38} -> clean\n```\n'], ["high-cancellation", '---\nid: high-cancellation\nname: Excessive Cancellations\ngroup: session-hygiene\nseverity: medium\nscope: requests\nversion: 1\ntags: [session, cancellation, waste]\nthresholds:\n  maxCancelRate: 0.15\n  highSeverityRate: 0.3\n---\n\n# Description\nDetects a high rate of cancelled requests, which wastes premium quota and indicates unclear prompting.\n\n# When Triggered\n{{count}} of {{total}} requests cancelled ({{pct}}). This wastes premium quota.\n\n# How to Improve\nWrite clearer, more specific prompts. Wait for responses instead of cancelling prematurely.\n\n# Examples\n"{{message}}..."\n\n# Detection Logic\n```detect\nscan: requests\nmatch: isCanceled == true\naggregate: ratio\ncheck: ratio > thresholds.maxCancelRate\nexamples: "{{messageText | clip:80}}"\n```\n'], ["instruction-bloat", '---\nid: instruction-bloat\nname: Instruction Bloat\ngroup: prompt-quality\nseverity: medium\nscope: sessions\nrequiresIdeContext: true\nversion: 1\ntags: [tokens, instructions, context, cost]\nthresholds:\n  maxBytes: 4000\n  minBloated: 1\n---\n\n# Description\nDetects oversized `.github/copilot-instructions.md` (or equivalent) files. Custom instructions are prepended to **every** request\'s system prompt \u2014 large files inflate input tokens on every turn, often by thousands of tokens that are never relevant to the current task.\n\n# When Triggered\n{{extra.bloatedSessions}} workspace(s) have custom-instruction files larger than {{thresholds.maxBytes}} bytes (largest: {{extra.maxBytes}} bytes). Every request in those workspaces pays the bloat cost on input tokens.\n\n# How to Improve\nTrim `.github/copilot-instructions.md` to the essentials: language/framework conventions, code style, "do not" rules, and pointers to longer docs. Move long examples and rationale into separate files referenced via `#file:`. Keep the always-on payload under ~4 KB.\n\n# Examples\n{{extra.maxBytes}} bytes \u2014 largest custom-instructions file across {{extra.totalSessions}} workspace(s)\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: true\naggregate: count\nstats: instructionBloatStats(allSessions, thresholds.maxBytes)\nbloatedSessions: stats.bloatedSessions\nmaxBytes: stats.maxBytes\ntotalSessions: stats.totalSessions\nwithInstructionsCount: stats.withInstructionsCount\nemitCount: stats.bloatedSessions\nemitTotal: stats.totalSessions\ncheck: stats.bloatedSessions >= thresholds.minBloated\nexamples: {{maxBytes}} bytes (workspace-level)\n```\n'], ["late-night-coding", '---\nid: late-night-coding\nname: Late-Night Coding\ngroup: session-hygiene\nseverity: low\nscope: requests\nversion: 1\ntags: [session, health, hours]\nthresholds:\n  lateNightHour: 5\n  minSample: 10\n---\n\n# Description\nDetects requests made between midnight and early morning. Late-night coding correlates with more bugs and lower quality output.\n\n# When Triggered\n{{count}} requests were made between midnight and {{extra.lateNightHour}}am. Late-night coding correlates with more bugs and lower quality.\n\n# How to Improve\nConsider establishing healthier work hours. Quality drops significantly when fatigued.\n\n# Examples\n{{extra.timestamp}}: "{{message}}..."\n\n# Detection Logic\n```detect\nscan: requests\nmatch: timestamp > 0 AND hour(timestamp) >= 0 AND hour(timestamp) < thresholds.lateNightHour\naggregate: count\ncheck: count > thresholds.minSample\nexamples: "{{messageText | truncate:50}}"\n```\n'], ["lazy-prompting", '---\nid: lazy-prompting\nname: Lazy Prompting\ngroup: prompt-quality\nseverity: medium\nscope: requests\nversion: 1\ntags: [prompt, quality, short]\nthresholds:\n  minChars: 30\n  maxRatio: 0.3\n  minSample: 10\n---\n\n# Description\nDetects requests with very short prompts that lack sufficient context for the AI to produce quality results.\n\n# When Triggered\n{{count}} requests ({{pct}}) are under {{extra.minChars}} characters. Very short prompts often produce poor results.\n\n# How to Improve\nProvide more context in your prompts: describe the intent, constraints, and expected output format.\n\n# Examples\n"{{message}}" ({{extra.charCount}} chars)\n\n# Detection Logic\n```detect\nscan: requests\nmatch: messageLength < thresholds.minChars AND messageLength > 0\naggregate: ratio\ncheck: ratio > thresholds.maxRatio AND count > thresholds.minSample\nexamples: "{{messageText | truncate:80}}" ({{messageLength}} chars)\n```\n\n# Tests\n```test\n{messageText: "fix bug", messageLength: 7} -> triggered\n{messageText: "Refactor the authentication middleware to use JWT tokens and add refresh token rotation", messageLength: 88} -> clean\n{messageText: "", messageLength: 0} -> clean\n```\n'], ["low-constraint-usage", '---\nid: low-constraint-usage\nname: Low Constraint Usage\ngroup: prompt-quality\nseverity: medium\nscope: requests\nversion: 1\ntags: [prompt, constraints, quality]\nthresholds:\n  minReqs: 30\n  minMessageLength: 40\n  constraintRate: 0.08\npatterns:\n  constraintKeywords: ["\\\\b(do not|don\'t|must not|never|without|avoid|only|strictly|limit to|at most|at least|no more than|require|restrict|exclude|ensure|must|shall)\\\\b"]\n---\n\n# Description\nDetects prompts that lack constraint keywords (do not, must, avoid, only, etc.). Constraints narrow AI output, reduce hallucinations, and produce higher-quality code.\n\n# When Triggered\nOnly {{extra.constraintPct}}% of prompts include constraints ({{extra.withConstraints}}/{{extra.substantialReqs}}). Constraints narrow AI output, reduce hallucinations, and produce higher-quality code.\n\n# How to Improve\nAdd explicit constraints to prompts: "do not use class components", "only use async/await", "limit to 50 lines", "avoid external dependencies". Negative constraints force the model out of boilerplate patterns and into more precise solutions.\n\n# Examples\n"{{message}}..." (no constraints)\n\n# Detection Logic\n```detect\nscan: requests\nmatch: messageLength >= thresholds.minMessageLength AND NOT \\\n  matches(messageText, "(?i)\\\\b(do not|don\'t|must not|never|without|avoid|only|strictly|limit to|at most|at least|no more than|require|restrict|exclude|ensure|must|shall|should not)\\\\b")\naggregate: count\nsubstantialTotal: countWhere(all, "messageLength", ">=", thresholds.minMessageLength)\nwithConstraints: substantialTotal - count\nsubstantialReqs: substantialTotal\nconstraintPct: round((substantialTotal - count) / substantialTotal * 100)\ncheck: substantialTotal >= thresholds.minReqs AND count / substantialTotal > (1 - thresholds.constraintRate)\nexamples: "{{messageText | truncate:80}}" (no constraints)\n```\n'], ["low-markdown-ratio", '---\nid: low-markdown-ratio\nname: Low Markdown Output Ratio\ngroup: prompt-quality\nseverity: medium\nscope: sessions\nversion: 1\ntags: [prompt, markdown, documentation]\nthresholds:\n  markdownRatio: 0.05\n  minTotalLoc: 100\n  minWorkspaces: 1\nfileTypes:\n  documentation: [markdown, md, mdx, txt, rst, adoc]\npatterns:\n  docFileExtensions: [md, mdx, txt, rst, adoc]\n---\n\n# Description\nDetects workspaces that produce almost no markdown output, suggesting specs, plans, and documentation are skipped before coding.\n\n# When Triggered\n{{count}} workspace(s) produce almost no markdown ({{extra.overallPct}}% of AI output). {{extra.totalCodeLoc}} LoC of code vs {{extra.totalMdLoc}} LoC of markdown. This suggests you skip writing specs, plans, and documentation before coding.\n\n# How to Improve\nAdopt spec-driven development: ask Copilot to draft a spec, plan, or design doc before writing code. Even a short markdown outline dramatically improves code quality and reduces iteration cycles. Try starting sessions with "Write a brief spec for..." or "Draft an implementation plan for...".\n\n# Examples\n{{extra.workspace}}: {{extra.codeLoc}} code LoC, {{extra.mdLoc}} markdown LoC ({{extra.ratioPct}}%)\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: true\naggregate: count\nmd: mdRatioByWorkspace(allSessions, thresholds.minTotalLoc, ["markdown", "md"])\nemitCount: md.lowCount\nemitTotal: md.totalWorkspaces\noverallPct: round(md.overallRatio * 100)\ntotalCodeLoc: md.totalCodeLoc\ntotalMdLoc: md.totalMdLoc\nworkspaces: md.workspaces\ncheck: md.lowCount >= thresholds.minWorkspaces\nseverity: md.overallRatio < 0.02\n```\n'], ["mcp-tool-bloat", '---\nid: mcp-tool-bloat\nname: Tool / MCP Bloat\ngroup: tool-mastery\nseverity: medium\nscope: sessions\nversion: 2\ntags: [tools, mcp, context-window]\nthresholds:\n  maxToolsPerSession: 40\n  minSessions: 3\n---\n\n# Description\nDetects sessions with an unusually large number of distinct tools invoked \u2014 a proxy for oversized tool catalogs that inflate every request\'s system prompt. Each registered tool adds tokens regardless of whether it\'s used.\n\n# When Triggered\n{{count}} session(s) used more than {{thresholds.maxToolsPerSession}} distinct tools. Large tool sets add silent overhead to every prompt.\n\n# How to Improve\nTrim the active toolset: disable rarely-used MCP servers, scope tool sets per workspace, and use tool groups so only relevant tools are loaded for the task at hand. Aim for under 40 active tools per session.\n\n# Examples\n{{flatUnique(reqs, "toolsUsed")}} tools in one session\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: flatUnique(reqs, "toolsUsed") > thresholds.maxToolsPerSession\naggregate: count\ncheck: count >= thresholds.minSessions\nexamples: {{flatUnique(reqs, "toolsUsed")}} tools\n```\n'], ["mega-sessions", "---\nid: mega-sessions\nname: Mega Sessions\ngroup: session-hygiene\nseverity: high\nscope: sessions\nversion: 1\ntags: [session, length, context]\nthresholds:\n  maxMessages: 50\n---\n\n# Description\nDetects sessions with an excessive number of messages. Long sessions degrade context quality and response accuracy.\n\n# When Triggered\n{{count}} session(s) have {{extra.maxMessages}}+ messages. Long sessions degrade context quality and response accuracy.\n\n# How to Improve\nStart new sessions periodically. Break large tasks into focused conversations of 15-25 messages.\n\n# Examples\n{{extra.workspace}}: {{extra.messageCount}} messages\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: requestCount >= thresholds.maxMessages\naggregate: count\ncheck: count > 0\nexamples: {{workspaceName}}: {{requestCount}} messages\n```\n"], ["model-overreliance", "---\nid: model-overreliance\nname: Model Overreliance\ngroup: tool-mastery\nseverity: medium\nscope: requests\nversion: 1\ntags: [tools, model, diversity]\nthresholds:\n  maxTopModelRate: 0.8\n  minSample: 10\n  minModels: 3\n---\n\n# Description\nDetects when the vast majority of requests use a single model, missing opportunities to use lighter models for simple tasks.\n\n# When Triggered\n{{pct}} of requests use {{extra.topModel}}. Different tasks benefit from different models.\n\n# How to Improve\nUse lighter models (gpt-4.1-mini, gemini-flash) for simple tasks to save premium quota and get faster responses.\n\n# Examples\n{{extra.model}}: {{extra.reqCount}} requests\n\n# Detection Logic\n```detect\nscan: requests\nmatch: true\naggregate: count\nmodels: modelStats(allReqs)\nemitCount: models.topCount\nemitTotal: models.total\ntopModel: models.topModel\ncheck: models.topShare > thresholds.maxTopModelRate AND models.modelCount < thresholds.minModels AND models.total > thresholds.minSample\n```\n"], ["no-custom-instructions", "---\nid: no-custom-instructions\nname: No Custom Instructions\ngroup: tool-mastery\nseverity: medium\nscope: requests\nrequiresIdeContext: true\nversion: 1\ntags: [tools, instructions, personalization]\nthresholds:\n  minRate: 0.05\n  minReqs: 20\n---\n\n# Description\nDetects when very few requests use custom instructions, missing out on personalized and project-specific responses.\n\n# When Triggered\nOnly {{extra.usagePct}}% of requests use custom instructions ({{extra.withInstructions}}/{{total}}). Missing out on personalized responses.\n\n# How to Improve\nCreate a .github/copilot-instructions.md or .instructions.md file in your workspace to give Copilot persistent context about your project conventions, stack, and coding style.\n\n# Examples\n{{extra.withInstructions}} of {{total}} requests had custom instructions\n\n# Detection Logic\n```detect\nscan: requests\nmatch: customInstructions.length == 0\naggregate: count\nusageRate: (total - count) / total\nwithInstructions: total - count\nusagePct: round(usageRate * 100)\ncheck: usageRate < thresholds.minRate AND total > thresholds.minReqs\n```\n"], ["no-devcontainer", "---\nid: no-devcontainer\nname: Unsandboxed Terminal Execution\ngroup: code-review\nseverity: medium\nscope: both\nrequiresIdeContext: true\nversion: 1\ntags: [review, security, devcontainer, terminal]\nthresholds:\n  minTerminalReqs: 20\n  terminalRate: 0.2\n---\n\n# Description\nDetects terminal commands that ran on the host machine instead of inside a devcontainer. Per-session detection: a session is considered sandboxed when its runtime data shows `/workspaces/...` paths (the Codespaces / Remote-Containers convention). Sessions without that evidence are treated as host-execution and counted here.\n\n# When Triggered\n{{count}} terminal commands ({{pct}} of VS Code requests) ran directly on your host machine without a devcontainer. Agent-driven terminal commands can modify system state, install packages, or delete files outside the project.\n\n# How to Improve\nSet up a .devcontainer/devcontainer.json (or use a Codespace) to sandbox AI-driven terminal execution. Devcontainers isolate builds, installs, and destructive commands from your host OS \u2014 especially important when using agent mode with auto-approved terminal access.\n\n# Examples\n$ {{extra.command}}\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: true\naggregate: count\ndc: devcontainerStats(allSessions, allReqs)\nemitCount: dc.terminalReqs\nemitTotal: dc.vscodeReqs\ncheck: dc.terminalReqs >= thresholds.minTerminalReqs AND dc.terminalRate >= thresholds.terminalRate\n```\n"], ["no-file-context", '---\nid: no-file-context\nname: Missing File Context\ngroup: prompt-quality\nseverity: medium\nscope: requests\nrequiresIdeContext: true\nversion: 1\ntags: [prompt, context, files]\nthresholds:\n  maxNoContextRate: 0.7\n  minSample: 10\n---\n\n# Description\nDetects requests that have no file references, meaning Copilot cannot see the relevant code context.\n\n# When Triggered\n{{pct}} of requests have no file references. Copilot gives better answers with file context.\n\n# How to Improve\nUse #file to reference relevant files, or open files in the editor so Copilot can use them as context.\n\n# Examples\n"{{message}}..."\n\n# Detection Logic\n```detect\nscan: requests\nmatch: referencedFiles.length == 0 AND editedFiles.length == 0\naggregate: ratio\ncheck: ratio > thresholds.maxNoContextRate AND count > thresholds.minSample\nexamples: "{{messageText | clip:80}}"\n```\n'], ["no-language-exploration", "---\nid: no-language-exploration\nname: No Language Exploration\ngroup: code-review\nseverity: low\nscope: requests\nversion: 1\ntags: [review, languages, exploration]\nthresholds:\n  minSample: 10\n  minWeeks: 4\n  recentWeeks: 8\n---\n\n# Description\nDetects when no new programming languages have been explored recently, despite AI being a learning accelerator.\n\n# When Triggered\nYou've used {{extra.totalLanguages}} languages total, but haven't explored a new one in {{count}} weeks. AI is a learning accelerator -- use it to try new languages and frameworks.\n\n# How to Improve\nAI coding assistants dramatically lower the barrier to learning new languages. Try asking Copilot to help you build something small in a language you haven't used before. Start with \"Write a simple HTTP server in [Go/Rust/Elixir]\" to break the ice.\n\n# Examples\n{{extra.languageList}}\n\n# Detection Logic\n```detect\nscan: requests\nmatch: timestamp > 0\naggregate: count\nlang: langExplorationWeeks(allReqs)\nemitCount: lang.weeksSinceNew\nemitTotal: lang.totalWeeks\ntotalLanguages: lang.totalLangs\ncheck: lang.recentNew == 0 AND lang.totalWeeks >= thresholds.minWeeks\nseverity: lang.weeksSinceNew > 12\n```\n"], ["no-plan-mode", '---\nid: no-plan-mode\nname: Never Uses Plan Mode\ngroup: tool-mastery\nseverity: medium\nscope: requests\nrequiresIdeContext: true\nversion: 1\ntags: [tools, planning, agent]\nthresholds:\n  minReqs: 30\n  agentRate: 0.3\n---\n\n# Description\nDetects heavy agentic usage with no use of plan mode, which helps the agent understand scope before implementation.\n\n# When Triggered\n{{extra.agenticReqs}} agentic requests but no use of plan mode. Jumping straight to implementation often leads to wrong approaches.\n\n# How to Improve\nUse plan mode (or /plan) before complex tasks. Planning helps the agent understand scope, break down work, and avoid wasted iterations.\n\n# Examples\nSwitch to Plan mode in the mode picker before starting large features\nUse /plan to outline an approach before coding\nPlan first, then switch to Agent mode to execute\n\n# Detection Logic\n```detect\nscan: requests\nmatch: agentMode == "agent" OR agentName != ""\naggregate: count\nagentRatio: count / total\nplanUsage: someWhere(all, "slashCommand", "plan") OR \\\n  someWhere(all, "agentMode", "matches", "(?i)plan"slashCommand", "plan") OR \\\n  someWhere(all, "agentMode", "matches", "(?i)plan")\nagenticReqs: count\ncheck: planUsage == 0 AND total >= thresholds.minReqs AND agentRatio >= thresholds.agentRate\n```\n'], ["no-skills", "---\nid: no-skills\nname: No Skills Usage\ngroup: tool-mastery\nseverity: low\nscope: requests\nrequiresIdeContext: true\nversion: 1\ntags: [tools, skills, domain]\nthresholds:\n  minReqs: 50\n---\n\n# Description\nDetects when no requests use Copilot skills, missing out on specialized domain knowledge.\n\n# When Triggered\nNo requests use Copilot skills. Skills provide specialized domain knowledge beyond general coding.\n\n# How to Improve\nExplore available skills in your IDE. Skills can help with specific frameworks, cloud providers, and development workflows.\n\n# Examples\nSkills extend Copilot with domain expertise\nCheck VS Code extensions for available skills\n\n# Detection Logic\n```detect\nscan: requests\nmatch: skillsUsed.length == 0\naggregate: count\ncheck: count == total AND total > thresholds.minReqs\n```\n"], ["no-slash-commands", '---\nid: no-slash-commands\nname: No Slash Commands\ngroup: tool-mastery\nseverity: low\nscope: requests\nrequiresIdeContext: true\nversion: 1\ntags: [tools, slash, commands]\nthresholds:\n  minRate: 0.02\n  minReqs: 20\n---\n\n# Description\nDetects low usage of slash commands, which produce more targeted responses than freeform prompts.\n\n# When Triggered\nOnly {{extra.withSlash}} of {{total}} requests use slash commands. Slash commands produce more targeted responses.\n\n# How to Improve\nTry /fix for bugs, /explain for understanding code, /tests for test generation, /doc for documentation.\n\n# Examples\n/fix - Fix bugs in selected code\n/explain - Explain how code works\n/tests - Generate unit tests\n\n# Detection Logic\n```detect\nscan: requests\nmatch: slashCommand == ""\naggregate: count\nusageRate: (total - count) / total\nwithSlash: total - count\ncheck: usageRate < thresholds.minRate AND total > thresholds.minReqs\n```\n'], ["no-spec-driven-development", '---\nid: no-spec-driven-development\nname: No Spec-Driven Development\ngroup: prompt-quality\nseverity: medium\nscope: sessions\nversion: 1\ntags: [prompt, spec, planning]\nthresholds:\n  minAgentSessions: 5\n  specRate: 0.2\n  planRate: 0.15\npatterns:\n  specFileExts: "(?i)\\\\.(md|txt|spec|prd|design|plan|rfc|adoc)$"\n  specKeywords: "(?i)\\\\b(spec|requirements?|acceptance criteria|design doc|PRD|RFC|plan file|constraint|must|should|ensure)\\\\b"\n  bulletList: "(?m)^[-*]\\\\s"\n  numberedList: "(?m)^\\\\d+[.)]\\\\s"\n  headings: "(?m)^#+\\\\s"\n---\n\n# Description\nDetects when few sessions start with specs, plans, or structured requirements. Spec-first development consistently beats vibe-coding.\n\n# When Triggered\nOnly {{extra.specDrivenCount}} of {{extra.totalSessions}} sessions ({{extra.specPct}}%) start with specs, plans, or structured requirements. Spec-first development consistently beats vibe-coding.\n\n# How to Improve\nAdopt Spec-Driven Development (SDD): write a brief spec before coding.\nHow sessions are classified:\n- Spec-driven: first prompt references a .md/.spec file, contains structured bullet points/numbered lists, uses keywords like "requirements", "acceptance criteria", "must", "ensure", or starts in plan mode.\n- Planning: any request uses plan mode (/plan) or contains planning keywords (plan, architect, design, outline, roadmap).\n- Unstructured: everything else \u2014 typically vague, single-sentence prompts that lead to more iterations.\nStart each session with: 1) What you\'re building, 2) Acceptance criteria, 3) Constraints. Even 3 bullet points dramatically improve AI output quality.\n\n# Examples\n{{extra.workspace}}: "{{message}}..."\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: requestCount >= 3 AND NOT (\\\n  anyMatch(first(requests).referencedFiles, patterns.specFileExts) OR \\\n  matches(first(requests).messageText, patterns.specKeywords) OR \\\n  (matches(first(requests).messageText, patterns.bulletList) AND lineCount(first(requests).messageText) >= 3) OR \\\n  (matches(first(requests).messageText, patterns.numberedList) AND lineCount(first(requests).messageText) >= 3) OR \\\n  matches(first(requests).messageText, patterns.headings) OR \\\n  first(requests).slashCommand == "plan" OR \\\n  contains(str(first(requests).agentMode), "plan"))\naggregate: count\nspecSessionTotal: countWhere(all, "requestCount", ">=", 3)\nspecRate: (specSessionTotal - count) / specSessionTotal\nspecDrivenCount: specSessionTotal - count\ntotalSessions: specSessionTotal\nspecPct: round(specRate * 100)\ncheck: specSessionTotal >= thresholds.minAgentSessions AND specRate < thresholds.specRate\nexamples: {{workspaceName}}: not spec-driven\n```\n'], ["no-spec-structure", '---\nid: no-spec-structure\nname: Unstructured Task Starts\ngroup: prompt-quality\nseverity: medium\nscope: sessions\nversion: 1\ntags: [prompt, structure, agentic]\nthresholds:\n  minAgentSessions: 5\n  structuredRate: 0.15\n---\n\n# Description\nDetects agentic sessions that start with vague, unstructured prompts lacking bullet points, requirements, or acceptance criteria.\n\n# When Triggered\n{{count}} of {{extra.agentSessions}} agentic sessions start with vague, unstructured prompts. No bullet points, requirements, or acceptance criteria.\n\n# How to Improve\nStart agentic sessions with structured specs: use bullet points, numbered requirements, or acceptance criteria. The more specific the first prompt, the better the result.\n\n# Examples\n{{extra.workspace}}: "{{message}}..."\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: requestCount >= 3 AND someWhere(requests, "agentMode", "agent") AND NOT (\\\n  matches(first(requests).messageText, "(?m)^[-*]\\\\s") OR \\\n  matches(first(requests).messageText, "(?m)^\\\\d+[.)]\\\\s") OR \\\n  matches(first(requests).messageText, "(?m)^#+\\\\s") OR \\\n  matches(first(requests).messageText, "(?i)\\\\b(requirements?|spec|acceptance criteria|user stories?|given|when|then|should|must)\\\\b") OR \\\n  lineCount(first(requests).messageText) >= 4)\naggregate: count\nagentSessionTotal: countWhere(all, "requestCount", ">=", 3)\nagentSessions: agentSessionTotal\ncheck: agentSessionTotal >= thresholds.minAgentSessions AND count / agentSessionTotal > (1 - thresholds.structuredRate)\nexamples: {{workspaceName}}: unstructured first prompt\n```\n'], ["premium-for-lookup-questions", '---\nid: premium-for-lookup-questions\nname: Premium Model for Lookup Questions\ngroup: tool-mastery\nseverity: medium\nscope: requests\nversion: 1\ntags: [model, lookup, ask, cost]\nthresholds:\n  minSample: 10\n  maxRatio: 0.1\n  maxMessageLength: 120\n---\n\n# Description\nDetects "lookup-style" questions ("what is X?", "where is Y?", "how do I Z?", "explain Y") that get routed to a premium model. These factual one-shot questions rarely need top-tier reasoning \u2014 `auto` or a base model usually returns the same answer for a fraction of the cost.\n\n# When Triggered\n{{count}} lookup-style questions ({{pct}}) used a premium model. Short factual questions almost never benefit from premium reasoning \u2014 they overpay on every request.\n\n# How to Improve\nSwitch the default model to `auto` so lightweight questions are routed cheaply. Reserve premium models for tasks that need actual reasoning: planning, debugging, multi-step refactors. Custom-instruct your IDE to "use the cheapest model that can answer this" for short prompts.\n\n# Examples\n{{normalizeModel(modelId)}}: "{{messageText | truncate:60}}"\n\n# Detection Logic\n```detect\nscan: requests\nmatch: modelTier(modelId) >= 1 AND messageLength > 0 AND messageLength < thresholds.maxMessageLength AND length(aiCode) == 0 AND length(toolsUsed) == 0 AND matches(messageText, "(?i)^\\\\s*(what(?:\'s| is| are)|where(?:\'s| is| are)|how do (?:i|you)|explain|why (?:does|is|are)|when (?:should|do)|which|tell me about|define)\\\\b")\naggregate: ratio\ncheck: ratio > thresholds.maxRatio AND count > thresholds.minSample\nexamples: {{normalizeModel(modelId)}}: "{{messageText | truncate:60}}"\n```\n'], ["premium-waste", '---\nid: premium-waste\nname: Premium Model Waste\ngroup: tool-mastery\nseverity: medium\nscope: requests\nversion: 1\ntags: [tools, model, waste, premium]\nthresholds:\n  minSample: 10\n  maxMessageLength: 50\n---\n\n# Description\nDetects simple requests (short prompt, no code output) that use premium models unnecessarily.\n\n# When Triggered\n{{count}} simple requests (short prompt, no code output) used premium models.\n\n# How to Improve\nUse lighter models for quick questions and simple tasks. Reserve premium models for complex code generation.\n\n# Examples\n{{extra.model}}: "{{message}}..."\n\n# Detection Logic\n```detect\nscan: requests\nmatch: modelTier(modelId) >= 1 AND messageLength < thresholds.maxMessageLength AND messageLength > 0 AND aiCode.length == 0\naggregate: count\ncheck: count > thresholds.minSample\nexamples: {{normalizeModel(modelId)}}: "{{messageText | truncate:50}}"\n```\n'], ["profanity", '---\nid: profanity\nname: Hostile Language\ngroup: prompt-quality\nseverity: medium\nscope: requests\nversion: 1\ntags: [prompt, profanity, hostile]\nthresholds:\n  minReqs: 1\n---\n\n# Description\nDetects requests containing profanity or hostile language, which usually signals deep frustration with the tool.\n\n# When Triggered\n{{count}} requests contain profanity or hostile language. This usually signals deep frustration with the tool.\n\n# How to Improve\nWhen you catch yourself using hostile language, take a break. Start a fresh session, rephrase the problem from scratch, or switch to a different approach entirely.\n\n# Examples\n{{extra.highlighted}} in: "{{message}}"\n\n# Detection Logic\n```detect\nscan: requests\nmatch: messageLength > 0 AND hasProfanity(messageText)\naggregate: count\ncheck: count >= thresholds.minReqs\nexamples: "{{messageText | truncate:60}}"\n```\n'], ["reasoning-effort-overuse", '---\nid: reasoning-effort-overuse\nname: Reasoning Effort Overuse\ngroup: tool-mastery\nseverity: medium\nscope: requests\nversion: 1\ntags: [model, reasoning, effort, cost]\nthresholds:\n  minSample: 20\n  maxRatio: 0.5\n---\n\n# Description\nDetects sessions where high or maximum reasoning effort is used for the majority of requests on reasoning-capable models. Higher reasoning levels generate many extra "thinking" tokens \u2014 every `-high` or `-xhigh` request typically costs 2\u20134\xD7 more output tokens than `-medium` or default for the same answer.\n\n# When Triggered\n{{extra.premiumCount}} of {{extra.totalKnown}} requests with a known reasoning level ({{pct}}) ran at `high` or `max` effort. These extra thinking tokens are billed even when the task doesn\'t need deep reasoning.\n\n# How to Improve\nDefault to `medium` effort and only escalate when the task actually benefits from extra reasoning (complex algorithms, ambiguous spec, multi-step planning). For routine edits, refactors, or factual questions, lower effort delivers the same result for a fraction of the output tokens.\n\n# Examples\n{{normalizeModel(modelId)}} \xB7 effort: {{reasoningEffort}}\n\n# Detection Logic\n```detect\nscan: requests\nmatch: reasoningEffort == "high" OR reasoningEffort == "max"\naggregate: count\nstats: reasoningEffortStats(allReqs, "high")\nemitCount: stats.premiumCount\nemitTotal: stats.totalKnown\npremiumCount: stats.premiumCount\ntotalKnown: stats.totalKnown\ncheck: stats.totalKnown > thresholds.minSample AND stats.ratio > thresholds.maxRatio\nexamples: {{normalizeModel(modelId)}} \xB7 effort: {{reasoningEffort}}\n```\n'], ["repeated-prompts", '---\nid: repeated-prompts\nname: Repeated Prompts\ngroup: prompt-quality\nseverity: medium\nscope: requests\nversion: 1\ntags: [prompt, duplicate, waste]\nthresholds:\n  minDuplicates: 3\n  highThreshold: 20\n---\n\n# Description\nDetects near-duplicate prompts that waste quota without producing new results.\n\n# When Triggered\n{{count}} requests are near-duplicates across {{extra.distinctCount}} distinct prompts. This wastes quota without new results.\n\n# How to Improve\nIf a prompt isn\'t working, rephrase it or provide more context instead of retrying the same message.\n\n# Examples\n"{{message}}..." (repeated {{extra.repeatCount}}x)\n\n# Detection Logic\n```detect\nscan: requests\nmatch: messageLength > 0\naggregate: count\ndupes: duplicateGroups(matched, 10, thresholds.minDuplicates)\nemitCount: dupes.totalDupes\nemitTotal: total\ndistinctCount: dupes.distinctCount\ncheck: dupes.totalDupes >= thresholds.minDuplicates\nseverity: dupes.totalDupes > thresholds.highThreshold\nexamples: "{{messageText | truncate:60}}"\n```\n'], ["runaway-agent-loops", '---\nid: runaway-agent-loops\nname: Runaway Agent Loops\ngroup: session-hygiene\nseverity: high\nscope: requests\nversion: 1\ntags: [session, agent, tools, loops]\nthresholds:\n  minToolsPerReq: 15\n  minReqs: 3\n---\n\n# Description\nDetects agentic requests that use an excessive number of tools per request, indicating the agent may be spinning on failing approaches.\n\n# When Triggered\n{{count}} agentic requests used {{extra.minToolsPerReq}}+ tools each (avg {{extra.avgTools}}). The agent may be spinning on failing approaches.\n\n# How to Improve\nBreak complex tasks into smaller, focused requests. If the agent is looping, cancel and rephrase with clearer constraints.\n\n# Examples\n{{extra.toolCount}} tools: "{{message}}..."\n\n# Detection Logic\n```detect\nscan: requests\nmatch: toolsUsed.length >= thresholds.minToolsPerReq AND (agentMode == "agent" OR agentName != "")\naggregate: count\ntotalTools: flatCount(matched, "toolsUsed")\navgTools: round(totalTools / count)\ncheck: count >= thresholds.minReqs\nexamples: {{toolsUsed.length}} tools: "{{messageText | truncate:60}}"\n```\n'], ["session-drift", "---\nid: session-drift\nname: Session Drift\ngroup: session-hygiene\nseverity: medium\nscope: sessions\nversion: 1\ntags: [session, focus, drift]\nthresholds:\n  maxWorkTypes: 4\n  minReqsPerSession: 5\n  minSessions: 3\n---\n\n# Description\nDetects sessions that cover too many different task types, confusing the AI context window.\n\n# When Triggered\n{{count}} sessions cover {{extra.maxWorkTypes}}+ different task types. Mixed-purpose sessions confuse the AI context.\n\n# How to Improve\nStart a new session when switching task types (bug fix to feature, docs to testing, etc.). Focused sessions get better responses.\n\n# Examples\n{{extra.workspace}}: {{extra.workTypes}}\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: requestCount >= thresholds.minReqsPerSession AND workTypeCount(requests) >= thresholds.maxWorkTypes\naggregate: count\ncheck: count > thresholds.minSessions\nexamples: {{workspaceName}}: {{workTypeCount(requests)}} work types in one session\n```\n"], ["slow-responses", '---\nid: slow-responses\nname: Slow Responses\ngroup: session-hygiene\nseverity: low\nscope: requests\nversion: 1\ntags: [session, performance, slow]\nthresholds:\n  slowMs: 30000\n  minCount: 5\n---\n\n# Description\nDetects requests with unusually long response times, which may indicate overly broad or complex prompts.\n\n# When Triggered\n{{count}} requests took over 30 seconds (avg {{extra.avgSec}}s). May indicate overly broad prompts.\n\n# How to Improve\nBreak complex tasks into smaller, focused requests. Use lighter models for simple questions.\n\n# Examples\n{{extra.elapsedSec}}s: "{{message}}..."\n\n# Detection Logic\n```detect\nscan: requests\nmatch: totalElapsed > thresholds.slowMs AND totalElapsed > 0\naggregate: count\navgSec: round(avgField(matched, "totalElapsed") / 1000)\ncheck: count > thresholds.minCount\nexamples: "{{messageText | truncate:50}}"\n```\n'], ["speed-accept", '---\nid: speed-accept\nname: Speed Accept (No Review)\ngroup: code-review\nseverity: high\nscope: sessions\nversion: 1\ntags: [review, speed, accept]\nthresholds:\n  minAiLoc: 20\n  maxGapMs: 15000\n  minOccurrences: 5\n---\n\n# Description\nDetects instances where the next message was sent within seconds of receiving large AI code blocks, indicating no time for review.\n\n# When Triggered\n{{count}} times you sent the next message within {{extra.maxGapSec}}s of receiving {{extra.minAiLoc}}+ lines of AI code (avg {{extra.avgLoc}} LOC, avg {{extra.avgGap}}s gap). Not enough time to review.\n\n# How to Improve\nTake time to read AI-generated code before moving on. Review for correctness, security issues, and edge cases. A quick glance is not a review.\n\n# Examples\n{{extra.workspace}}: {{extra.aiLoc}} AI LOC, {{extra.gapSec}}s gap -> "{{message}}..."\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: requestCount >= 2\naggregate: count\npairs: adjacentPairCount(allSessions, thresholds.minAiLoc, thresholds.maxGapMs)\nemitCount: pairs.count\nemitTotal: count\navgLoc: pairs.avgLoc\navgGap: pairs.avgGap\nmaxGapSec: round(thresholds.maxGapMs / 1000)\nminAiLoc: thresholds.minAiLoc\ncheck: pairs.count >= thresholds.minOccurrences\nexamples: {{workspaceName}}: speed-accept detected\n```\n'], ["tunnel-vision", '---\nid: tunnel-vision\nname: Single-Workspace Tunnel Vision\ngroup: code-review\nseverity: low\nscope: sessions\nversion: 1\ntags: [review, workspace, diversity]\nthresholds:\n  maxTopRate: 0.95\n  minReqs: 50\n  minWorkspaces: 3\n---\n\n# Description\nDetects when the vast majority of requests are concentrated in a single workspace, missing opportunities to use AI across projects.\n\n# When Triggered\n{{pct}} of all requests ({{count}}/{{total}}) are in "{{extra.topWorkspace}}". Copilot can help across all your projects.\n\n# How to Improve\nTry using Copilot in other workspaces too. It can help with documentation, testing, DevOps, and exploratory coding across your entire workflow.\n\n# Examples\n{{extra.workspace}}: {{extra.reqCount}} requests ({{extra.reqPct}}%)\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: true\naggregate: count\ntop: groupTopBySum(allSessions, "workspaceName", "requestCount")\nreqTotal: sumField(allSessions, "requestCount")\nemitCount: top.sum\nemitTotal: reqTotal\ntopWorkspace: top.key\ncheck: top.share > thresholds.maxTopRate AND top.sum >= thresholds.minReqs AND top.count >= thresholds.minWorkspaces\n```\n'], ["verbose-output", '---\nid: verbose-output\nname: Verbose Model Output\ngroup: prompt-quality\nseverity: medium\nscope: requests\nversion: 1\ntags: [tokens, output, verbosity, cost]\nthresholds:\n  minCompletionTokens: 5000\n  maxMessageLength: 200\n  minSample: 10\n  maxRatio: 0.1\n---\n\n# Description\nDetects requests where the AI generated very long responses (>5K completion tokens) for short, low-context prompts. These rambling outputs burn through completion-token budgets without proportional value.\n\n# When Triggered\n{{count}} requests ({{pct}}) produced >{{extra.minCompletionTokens}} completion tokens from prompts shorter than {{extra.maxMessageLength}} characters. Verbose outputs are a major driver of token spend.\n\n# How to Improve\nBe explicit about response length and format: ask for "a concise answer", "a one-line summary", "no commentary", or specify a maximum number of bullets. Add output constraints to your custom instructions for routine tasks.\n\n# Examples\n"{{messageText | truncate:80}}" \u2192 {{completionTokens}} completion tokens\n\n# Detection Logic\n```detect\nscan: requests\nmatch: completionTokens > thresholds.minCompletionTokens AND messageLength > 0 AND messageLength < thresholds.maxMessageLength\naggregate: ratio\ncheck: ratio > thresholds.maxRatio AND count > thresholds.minSample\nexamples: "{{messageText | truncate:80}}" \u2192 {{completionTokens}} tokens\n```\n\n# Tests\n```test\n{messageText: "fix this", messageLength: 8, completionTokens: 8000} -> triggered\n{messageText: "Explain in detail how the OAuth flow works including token refresh, PKCE, and edge cases for mobile clients", messageLength: 110, completionTokens: 8000} -> clean\n{messageText: "fix this", messageLength: 8, completionTokens: 200} -> clean\n```\n'], ["verbose-prompt-no-compression", '---\nid: verbose-prompt-no-compression\nname: Verbose Prompts Without Compression\ngroup: prompt-quality\nseverity: low\nscope: requests\nversion: 1\ntags: [prompt, verbosity, tokens, cost]\nthresholds:\n  minMessageLength: 800\n  minSample: 15\n  maxRatio: 0.2\n---\n\n# Description\nDetects user prompts that are unusually long and full of low-signal "fluff" words (please, kindly, thanks, basically, essentially, definitely, absolutely, simply, very, quite, somewhat, certainly). Long verbose prompts inflate input tokens on every turn \u2014 and where compression skills are available (e.g. caveman/cavecrew), the user is paying the verbosity tax twice (once on the user message, once on the system instructions).\n\n# When Triggered\n{{count}} verbose prompts ({{pct}}) of length \u2265{{thresholds.minMessageLength}} chars contained 2+ filler words. These prompts could be rewritten to half the size with no loss of meaning.\n\n# How to Improve\nBe terse and structured. Replace "please could you kindly write a function that basically just adds two numbers" with "write add(a,b)". Use bullet points instead of paragraphs. Drop pleasantries \u2014 Copilot doesn\'t care, and you pay for every token. Consider installing a compression skill like `caveman/cavecrew` to compress sub-agent results.\n\n# Examples\n"{{messageText | truncate:80}}" ({{messageLength}} chars)\n\n# Detection Logic\n```detect\nscan: requests\nmatch: messageLength >= thresholds.minMessageLength AND matches(messageText, "(?i)\\\\b(please|kindly|thanks|thank you|basically|essentially|definitely|absolutely|simply|very|quite|somewhat|certainly|actually|literally)\\\\b.*\\\\b(please|kindly|thanks|thank you|basically|essentially|definitely|absolutely|simply|very|quite|somewhat|certainly|actually|literally)\\\\b") AND hasSkillByPattern(allReqs, "(?i)cavecrew|caveman|compress") == 0\naggregate: ratio\ncheck: ratio > thresholds.maxRatio AND count > thresholds.minSample\nexamples: "{{messageText | truncate:80}}" ({{messageLength}} chars)\n```\n'], ["vibe-coding", '---\nid: vibe-coding\nname: Vibe Coding\ngroup: code-review\nseverity: high\nscope: sessions\nversion: 1\ntags: [review, vibe, quality]\nthresholds:\n  minAiLoc: 100\n  maxUserPrompts: 5\n  minSessions: 3\n---\n\n# Description\nDetects sessions with high AI code output from minimal prompts with no specs, indicating velocity without understanding.\n\n# When Triggered\n{{count}} sessions show vibe-coding patterns: {{extra.totalVibeLoc}} AI LoC generated with minimal prompts, no specs, and minimal review. Velocity without understanding creates knowledge debt.\n\n# How to Improve\nSlow down. Write specs before coding. Review generated code line by line. Understand what the AI produced before moving on. High LoC output without comprehension is technical debt, not productivity.\n\n# Examples\n{{extra.workspace}}: {{extra.aiLoc}} AI LoC in {{extra.messageCount}} messages -- "{{message}}..."\n\n# Detection Logic\n```detect\nscan: sessions\nmatch: flatSumField(requests, "aiCode", "loc") >= thresholds.minAiLoc AND \\\n  requestCount <= thresholds.maxUserPrompts AND NOT (\\\n  matches(first(requests).messageText, "(?m)^[-*]\\\\s") OR \\\n  matches(first(requests).messageText, "(?m)^\\\\d+[.)]\\\\s") OR \\\n  matches(first(requests).messageText, "(?m)^#+\\\\s") OR \\\n  matches(first(requests).messageText, "(?i)\\\\b(requirements?|spec|acceptance criteria|user stories?|given|when|then|should|must)\\\\b") OR \\\n  lineCount(first(requests).messageText) >= 4)\naggregate: count\ncheck: count >= thresholds.minSessions\nexamples: {{workspaceName}}: {{flatSumField(requests, "aiCode", "loc")}} AI LoC in {{requestCount}} messages\n```\n'], ["weekend-overwork", '---\nid: weekend-overwork\nname: Weekend Overwork\ngroup: session-hygiene\nseverity: low\nscope: requests\nversion: 1\ntags: [session, health, weekend]\nthresholds:\n  maxWeekendRate: 0.25\n  minWeekendReqs: 20\n---\n\n# Description\nDetects a high proportion of requests happening on weekends, which may indicate work-life balance issues.\n\n# When Triggered\n{{count}} requests ({{pct}}) happen on weekends. This may indicate work-life balance issues.\n\n# How to Improve\nConsider maintaining boundaries between work and personal time. Sustained overwork leads to burnout and decreased productivity.\n\n# Examples\n{{extra.weekendReqs}} weekend requests vs {{extra.weekdayReqs}} weekday requests\n\n# Detection Logic\n```detect\nscan: requests\nmatch: timestamp > 0 AND (dayOfWeek(timestamp) == 0 OR dayOfWeek(timestamp) == 6)\naggregate: ratio\ncheck: ratio > thresholds.maxWeekendRate AND count > thresholds.minWeekendReqs\nexamples: "{{messageText | truncate:50}}"\n```\n'], ["yolo-mode", "---\nid: yolo-mode\nname: YOLO Mode\ngroup: code-review\nseverity: high\nscope: requests\nrequiresIdeContext: true\nversion: 1\ntags: [review, security, auto-approve, unsupervised]\nthresholds:\n  autoApproveRate: 0.9\n  minConfirmations: 15\n---\n\n# Description\nDetects when the vast majority of tool actions are auto-approved, meaning the agent runs virtually unsupervised.\n\n# When Triggered\n{{count}} of {{total}} tool actions ({{pct}}) were auto-approved. The agent is running virtually unsupervised.\n\n# How to Improve\nDisable blanket auto-approve. Review file edits, terminal commands, and web searches individually. Use session-scoped approval only for trusted, low-risk tools.\n\n# Examples\nAuto-approved: {{extra.tools}}\n\n# Detection Logic\n```detect\nscan: requests\nmatch: toolConfirmations.length > 0\naggregate: count\nyolo: yoloStats(matched)\nemitCount: yolo.autoApproved\nemitTotal: yolo.totalConfirmations\ncheck: yolo.ratio > thresholds.autoApproveRate AND yolo.totalConfirmations >= thresholds.minConfirmations\n```\n"]];

